package ru.memearena.security;
import jakarta.servlet.*; import jakarta.servlet.http.*; import org.springframework.beans.factory.annotation.Value; import org.springframework.context.annotation.*; import org.springframework.http.HttpStatus; import org.springframework.security.authentication.*; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.config.http.SessionCreationPolicy; import org.springframework.security.core.authority.SimpleGrantedAuthority; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.security.web.*; import org.springframework.web.filter.OncePerRequestFilter; import org.springframework.security.web.authentication.HttpStatusEntryPoint; import org.springframework.security.web.authentication.www.BasicAuthenticationFilter; import org.springframework.stereotype.Component; import ru.memearena.error.*; import ru.memearena.session.infrastructure.UserSessionRepository; import ru.memearena.user.infrastructure.UserProfileRepository; import java.io.IOException; import java.time.Clock; import java.time.Instant; import java.util.*;
@Configuration public class SecurityConfig { @Bean SecurityFilterChain chain(HttpSecurity http, BearerAuthFilter f) throws Exception { return http.csrf(c->c.disable()).sessionManagement(s->s.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).exceptionHandling(e->e.authenticationEntryPoint(new HttpStatusEntryPoint(HttpStatus.UNAUTHORIZED)).accessDeniedHandler((req,res,ex)->{res.setStatus(403);res.setContentType("application/json");res.getWriter().write("{\"code\":\"ACCESS_DENIED\",\"message\":\"Access denied\"}");})).authorizeHttpRequests(a->a.requestMatchers("/api/v1/users/guest","/api/v1/health","/actuator/health","/api/v1/memes/top","/api/v1/media/*/content","/v3/api-docs/**","/swagger-ui/**","/swagger-ui.html").permitAll().requestMatchers("/api/v1/admin/**").hasRole("ADMIN").anyRequest().authenticated()).addFilterBefore(f,BasicAuthenticationFilter.class).build(); } }
@Component class BearerAuthFilter extends OncePerRequestFilter { private final UserSessionRepository sessions; private final UserProfileRepository users; private final TokenService tokens; private final Clock clock; private final String adminToken; BearerAuthFilter(UserSessionRepository s,UserProfileRepository u,TokenService t,Clock c,@Value("${app.admin-token:${MEME_ARENA_ADMIN_TOKEN:}}") String adminToken){this.sessions=s;this.users=u;this.tokens=t;this.clock=c;this.adminToken=adminToken;} protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException{String path=req.getRequestURI(); String h=req.getHeader("Authorization"); if(h!=null&&h.startsWith("Bearer ")){String raw=h.substring(7); if(path.startsWith("/api/v1/admin/")){ if(adminToken!=null&&!adminToken.isBlank()&&tokens.constantEquals(adminToken,raw)){var auth=new UsernamePasswordAuthenticationToken(new AdminPrincipal(),null,List.of(new SimpleGrantedAuthority("ROLE_ADMIN"))); SecurityContextHolder.getContext().setAuthentication(auth);} } else {String hash=tokens.sha256(raw); var opt=sessions.findByTokenHash(hash); if(opt.isPresent()){var s=opt.get(); Instant now=Instant.now(clock); if(!s.revoked()&&!s.expired(now)){users.findById(s.getUserId()).ifPresent(u->{s.touch(now);sessions.save(s); var p=new AuthenticatedUserPrincipal(u.getId(),u.getNickname(),s.getId()); SecurityContextHolder.getContext().setAuthentication(new UsernamePasswordAuthenticationToken(p,null,List.of(new SimpleGrantedAuthority("ROLE_USER"))));});}} }} chain.doFilter(req,res);} }
